13	  recentActivity: Array<{ title: string; at: string }>;
14	}
15	
16	const authStore = useAuthStore();
17	const loading = ref(false);
18	
19	const adminStats = ref<DashboardStats>({
20	  totalSessions: 0,
21	  upcomingSessions: 0,
22	  pendingReviews: 0,
23	  failedJobs: 0,
24	  pendingAntiCheatFlags: 0,
25	  recentActivity: [],
26	});
27	
28	const exams = ref<
29	  Array<{
30	    subjectName: string;
31	    examDate: string;
32	    startTime: string;
33	    roomName: string;
34	  }>
35	>([]);
36	
37	const isStudent = computed(() => authStore.activeRole === "STUDENT");
38	
39	onMounted(async () => {
40	  loading.value = true;
41	  try {
42	    if (isStudent.value) {
43	      exams.value = await unwrap(api.get("/my/exams"));
44	    } else {
45	      adminStats.value = await unwrap(api.get("/dashboard/stats"));
46	    }
47	  } catch {
48	    if (!isStudent.value) {
49	      adminStats.value = {
50	        totalSessions: 0,
51	        upcomingSessions: 0,
52	        pendingReviews: 0,
53	        failedJobs: 0,
54	        pendingAntiCheatFlags: 0,
55	        recentActivity: [],
56	      };
57	    }
58	  } finally {
59	    loading.value = false;
60	  }
61	});
62	</script>
