1	import axios, {
2	  AxiosError,
3	  type AxiosResponse,
4	  type InternalAxiosRequestConfig,
5	} from "axios";
6	import { createNonce, hashBody, signRequest } from "@/utils/crypto";
7	import type { AuthStore } from "@/stores/auth";
8	
9	export const api = axios.create({
10	  baseURL: "/api/v1",
11	  timeout: 20000,
12	});
13	
14	export function setupApiInterceptors(authStore: AuthStore): void {
15	  api.interceptors.request.use((config) => {
16	    const method = (config.method || "GET").toUpperCase();
17	    const requestPath = normalizePath(config);
18	
19	    if (!(method === "POST" && requestPath.endsWith("/auth/login"))) {
20	      const timestamp = String(Math.floor(Date.now() / 1000));
21	      const nonce = createNonce();
22	      const bodyHash = hashBody(config.data);
23	      const secret = authStore.sessionSecret || authStore.token;
24	
25	      if (secret) {
26	        const signature = signRequest({
27	          method,
28	          path: requestPath,
29	          timestamp,
30	          nonce,
31	          bodyHash,
32	          secret,
33	        });
34	
35	        config.headers.set("X-Timestamp", timestamp);
36	        config.headers.set("X-Nonce", nonce);
37	        config.headers.set("X-Signature", signature);
38	      }
39	    }
40	
41	    if (authStore.token) {
42	      config.headers.set("Authorization", `Bearer ${authStore.token}`);
43	    }
44	
45	    return config;
46	  });
47	
48	  api.interceptors.response.use(
49	    (response) => response,
50	    (error: AxiosError) => {
51	      if (error.response?.status === 401) {
52	        authStore.logout("SESSION_EXPIRED");
53	      }
54	      return Promise.reject(error);
55	    },
56	  );
57	}
58	
59	export async function unwrap(
60	  promise: Promise<AxiosResponse<any>>,
61	): Promise<any> {
62	  const response = await promise;
63	  if (
64	    response.data &&
65	    typeof response.data === "object" &&
66	    "data" in response.data
67	  ) {
68	    return response.data.data;
69	  }
70	  return response.data;
71	}
72	
73	function normalizePath(config: InternalAxiosRequestConfig): string {
74	  const raw = config.url || "";
75	
76	  try {
77	    if (raw.startsWith("http://") || raw.startsWith("https://")) {
78	      const parsed = new URL(raw);
79	      return `${parsed.pathname}${parsed.search}`;
80	    }
81	
82	    const basePath = new URL(
83	      config.baseURL || "",
84	      window.location.origin,
85	    ).pathname.replace(/\/$/, "");
86	    const normalizedRaw = raw.startsWith("/") ? raw : `/${raw}`;
87	    const merged = new URL(
88	      `${basePath}${normalizedRaw}`,
89	      window.location.origin,
90	    );
91	    return `${merged.pathname}${merged.search}`;
92	  } catch {
93	    return raw.startsWith("/") ? raw : `/${raw}`;
94	  }
95	}
