1	import { onBeforeUnmount, onMounted, ref, watch, type Ref } from "vue";
2	import { api, unwrap } from "@/api";
3	
4	export interface AutoSaveOptions<T extends Record<string, unknown>> {
5	  formKey: string;
6	  data: Ref<T>;
7	  enabled?: Ref<boolean>;
8	  intervalMs?: number;
9	}
10	
11	export function useAutoSave<T extends Record<string, unknown>>(
12	  options: AutoSaveOptions<T>,
13	) {
14	  const saving = ref(false);
15	  const lastSavedAt = ref<string>("");
16	  const error = ref("");
17	  const hasDraft = ref(false);
18	  let timer: number | undefined;
19	
20	  async function saveDraft(): Promise<void> {
21	    if (options.enabled && !options.enabled.value) {
22	      return;
23	    }
24	
25	    saving.value = true;
26	    error.value = "";
27	    try {
28	      await unwrap(api.put(`/drafts/${options.formKey}`, options.data.value));
29	      hasDraft.value = true;
30	      lastSavedAt.value = new Date().toISOString();
31	    } catch (err) {
32	      error.value = (err as Error).message;
33	    } finally {
34	      saving.value = false;
35	    }
36	  }
37	
38	  async function loadDraft(): Promise<T | null> {
39	    try {
40	      const data = await unwrap(api.get<T>(`/drafts/${options.formKey}`));
41	      hasDraft.value = true;
42	      return data;
43	    } catch {
44	      return null;
45	    }
46	  }
47	
48	  async function deleteDraft(): Promise<void> {
49	    try {
50	      await unwrap(api.delete(`/drafts/${options.formKey}`));
51	      hasDraft.value = false;
52	    } catch {
53	      // no-op
54	    }
55	  }
56	
57	  onMounted(() => {
58	    const interval = options.intervalMs || 30_000;
59	    timer = window.setInterval(() => {
60	      void saveDraft();
61	    }, interval);
62	  });
63	
64	  onBeforeUnmount(() => {
65	    if (timer) {
66	      window.clearInterval(timer);
67	    }
68	  });
69	
70	  watch(
71	    () => options.data.value,
72	    () => {
73	      error.value = "";
74	    },
75	    { deep: true },
76	  );
77	
78	  return {
79	    saving,
80	    lastSavedAt,
81	    error,
82	    hasDraft,
83	    saveDraft,
84	    loadDraft,
85	    deleteDraft,
86	  };
87	}
