5	export function useRBAC() {
6	  const authStore = useAuthStore();
7	
8	  const role = computed(() => authStore.activeRole as RoleName | "");
9	
10	  function canAny(roles: RoleName[]): boolean {
11	    if (!role.value) {
12	      return false;
13	    }
14	    return roles.includes(role.value as RoleName);
15	  }
16	
17	  return {
18	    role,
19	    canAny,
20	  };
21	}
