17	export function fromNow(value?: string | number | Date | null): string {
18	  if (!value) {
19	    return "-";
20	  }
21	  const minute = dayjs().diff(dayjs(value), "minute");
22	  if (minute <= 1) {
23	    return "just now";
24	  }
25	  return `${minute} min ago`;
