1	export function maskStudentId(
2	  value: string | number | undefined | null,
3	  showRaw = false,
4	): string {
5	  if (value === undefined || value === null || value === "") {
6	    return "-";
7	  }
8	
9	  const raw = String(value);
10	  if (showRaw || raw.length <= 4) {
11	    return raw;
12	  }
13	
14	  return `${"*".repeat(Math.max(0, raw.length - 4))}${raw.slice(-4)}`;
15	}
