1	import { computed, ref } from "vue";
2	import { defineStore } from "pinia";
3	import router from "@/router";
4	import { api, unwrap } from "@/api";
5	import type { LoginPayload, UserProfile } from "@/types/auth";
6	
7	const STORAGE_KEY = "secure-exam-auth";
8	
9	interface PersistedAuth {
10	  token: string;
11	  sessionSecret: string;
12	  user: UserProfile;
13	  rememberDevice: boolean;
14	  loginAt: number;
15	}
16	
17	export const useAuthStore = defineStore("auth", () => {
18	  const token = ref("");
19	  const sessionSecret = ref("");
20	  const user = ref<UserProfile | null>(null);
21	  const rememberDevice = ref(false);
22	  const loginAt = ref(0);
23	  const pendingDrafts = ref<Array<{ formKey: string; updatedAt: string }>>([]);
24	  const sessionWarningVisible = ref(false);
25	
26	  const isAuthenticated = computed(() => Boolean(token.value && user.value));
27	  const activeRole = computed(() => user.value?.activeRole || "");
28	  const availableRoles = computed(() => user.value?.roles || []);
29	
30	  const homePath = computed(() => {
31	    const role = activeRole.value;
32	    if (role === "STUDENT") {
33	      return "/student/exams";
34	    }
35	    return "/dashboard";
36	  });
37	
38	  async function login(input: {
39	    username: string;
40	    password: string;
41	    remember: boolean;
42	  }): Promise<void> {
43	    const payload = await unwrap(
44	      api.post<LoginPayload>("/auth/login", {
45	        username: input.username,
46	        password: input.password,
47	      }),
48	    );
49	
50	    token.value = payload.token;
51	    sessionSecret.value = payload.sessionSecret || payload.token;
52	    user.value = payload.user;
53	    rememberDevice.value = input.remember;
54	    loginAt.value = Date.now();
55	    pendingDrafts.value = payload.drafts || [];
56	
57	    if (pendingDrafts.value.length === 0) {
58	      try {
59	        const draftResult = await unwrap(
60	          api.get("/drafts", {
61	            params: { page: 1, size: 20 },
62	          }),
63	        );
64	        pendingDrafts.value = draftResult.items || draftResult || [];
65	      } catch {
66	        pendingDrafts.value = [];
67	      }
68	    }
69	
70	    persistSession();
71	  }
72	
73	  async function fetchProfile(): Promise<void> {
74	    const profile = await unwrap(api.get<UserProfile>("/auth/me"));
75	    user.value = profile;
76	    persistSession();
77	  }
78	
79	  async function switchRole(role: string): Promise<void> {
80	    const data = await unwrap(
81	      api.put<{ activeRole: string; scopes?: unknown }>("/auth/active-role", {
82	        role,
83	      }),
84	    );
85	    if (user.value) {
86	      user.value = {
87	        ...user.value,
88	        activeRole: data.activeRole,
89	        scopes: (data.scopes as UserProfile["scopes"]) || user.value.scopes,
90	      };
91	      persistSession();
92	    }
93	  }
94	
95	  function restoreSession(): void {
96	    const localRaw = localStorage.getItem(STORAGE_KEY);
97	    const sessionRaw = sessionStorage.getItem(STORAGE_KEY);
98	    const raw = localRaw || sessionRaw;
99	    if (!raw) {
100	      return;
101	    }
102	
103	    try {
104	      const parsed = JSON.parse(raw) as PersistedAuth;
105	      token.value = parsed.token;
106	      sessionSecret.value = parsed.sessionSecret;
107	      user.value = parsed.user;
108	      rememberDevice.value = parsed.rememberDevice;
109	      loginAt.value = parsed.loginAt;
110	    } catch {
111	      clearStorage();
112	    }
113	  }
114	
115	  function setPendingDrafts(
116	    drafts: Array<{ formKey: string; updatedAt: string }>,
117	  ): void {
118	    pendingDrafts.value = drafts;
119	  }
120	
121	  function setSessionWarning(visible: boolean): void {
122	    sessionWarningVisible.value = visible;
123	  }
124	
125	  async function logout(
126	    reason: "MANUAL" | "SESSION_EXPIRED" = "MANUAL",
127	  ): Promise<void> {
128	    if (token.value && reason === "MANUAL") {
129	      try {
130	        await api.post("/auth/logout");
131	      } catch {
132	        // no-op
133	      }
134	    }
135	
136	    token.value = "";
137	    sessionSecret.value = "";
138	    user.value = null;
139	    pendingDrafts.value = [];
140	    loginAt.value = 0;
141	    clearStorage();
142	
143	    if (router.currentRoute.value.name !== "login") {
144	      await router.push({ name: "login" });
145	    }
146	  }
147	
148	  function persistSession(): void {
149	    if (!token.value || !user.value) {
150	      return;
151	    }
152	
153	    const payload: PersistedAuth = {
154	      token: token.value,
155	      sessionSecret: sessionSecret.value,
156	      user: user.value,
157	      rememberDevice: rememberDevice.value,
158	      loginAt: loginAt.value,
159	    };
160	
161	    const raw = JSON.stringify(payload);
162	    if (rememberDevice.value) {
163	      localStorage.setItem(STORAGE_KEY, raw);
164	      sessionStorage.removeItem(STORAGE_KEY);
165	      return;
166	    }
167	
168	    sessionStorage.setItem(STORAGE_KEY, raw);
169	    localStorage.removeItem(STORAGE_KEY);
170	  }
171	
172	  function clearStorage(): void {
173	    localStorage.removeItem(STORAGE_KEY);
174	    sessionStorage.removeItem(STORAGE_KEY);
175	  }
176	
177	  return {
178	    token,
179	    sessionSecret,
180	    user,
181	    rememberDevice,
182	    loginAt,
183	    pendingDrafts,
184	    sessionWarningVisible,
185	    isAuthenticated,
186	    activeRole,
187	    availableRoles,
188	    homePath,
189	    login,
190	    logout,
191	    switchRole,
192	    fetchProfile,
193	    restoreSession,
194	    setPendingDrafts,
195	    setSessionWarning,
196	  };
197	});
198	
199	export type AuthStore = ReturnType<typeof useAuthStore>;
