  if (/[0-9]/.test(p)) score++;
  if (/[^A-Za-z0-9]/.test(p)) score++;
  if (score <= 1) return { level: 1, label: t("users.weak"), cls: "weak" };
  if (score <= 2) return { level: 2, label: t("users.medium"), cls: "medium" };
  return { level: 3, label: t("users.strong"), cls: "strong" };
});

