            <tr v-for="d in deliveries" :key="String(d.id)">
              <td>{{ d.recipientName || d.recipientId || '-' }}</td>
              <td>{{ d.channel || '-' }}</td>
              <td>
                <span class="status-badge" :class="d.status === 'DELIVERED' ? 'badge-green' : d.status === 'FAILED' ? 'badge-red' : 'badge-yellow'">
                  {{ d.status }}
                </span>
