2	import { appRoutes } from "@/router/routes";
3	import { useAuthStore } from "@/stores/auth";
4	
5	const router = createRouter({
6	  history: createWebHistory(),
7	  routes: appRoutes,
8	});
9	
10	router.beforeEach((to) => {
11	  const authStore = useAuthStore();
12	  const requiresAuth = Boolean(to.meta.requiresAuth);
13	  const roles = to.meta.roles as string[] | undefined;
14	
15	  if (requiresAuth && !authStore.isAuthenticated) {
16	    return {
17	      name: "login",
18	      query: { redirect: to.fullPath },
19	    };
20	  }
21	
22	  if (to.name === "login" && authStore.isAuthenticated) {
23	    return { path: authStore.homePath };
24	  }
25	
26	  if (
27	    roles &&
28	    roles.length > 0 &&
29	    authStore.activeRole &&
30	    !roles.includes(authStore.activeRole)
31	  ) {
32	    return { name: "forbidden" };
33	  }
34	
35	  if (to.path === "/" && authStore.isAuthenticated) {
36	    return { path: authStore.homePath };
37	  }
38	
39	  return true;
40	});
41	
42	router.afterEach((to) => {
43	  const title = (to.meta.title as string | undefined) || "Secure Exam System";
44	  document.title = `${title} | Secure Exam System`;
45	});
46	
47	export default router;
48

