9	@Component
10	public class PasswordPolicyValidator {
11	
12	    private static final Pattern UPPER = Pattern.compile(".*[A-Z].*");
13	    private static final Pattern LOWER = Pattern.compile(".*[a-z].*");
14	    private static final Pattern DIGIT = Pattern.compile(".*\\d.*");
15	    private static final Pattern SPECIAL = Pattern.compile(".*[^A-Za-z0-9].*");
16	
17	    public void validate(String password) {
18	        if (password == null || password.length() < 12
19	                || !UPPER.matcher(password).matches()
20	                || !LOWER.matcher(password).matches()
21	                || !DIGIT.matcher(password).matches()
22	                || !SPECIAL.matcher(password).matches()) {
23	            throw new BusinessException(ErrorCode.VALIDATION_FAILED, HttpStatus.BAD_REQUEST,
24	                    "Password must be at least 12 chars and include upper, lower, digit and special character");
25	        }
26	    }
27	}
