4	import com.exam.system.dto.ErrorDetail;
5	import jakarta.validation.ConstraintViolationException;
6	import java.time.Instant;
7	import java.util.List;
8	import java.util.stream.Collectors;
9	import org.springframework.http.HttpHeaders;
10	import org.springframework.http.HttpStatus;
11	import org.springframework.http.ResponseEntity;
12	import org.springframework.validation.FieldError;
13	import org.springframework.web.bind.MethodArgumentNotValidException;
14	import org.springframework.web.bind.annotation.ExceptionHandler;
15	import org.springframework.web.bind.annotation.RestControllerAdvice;
16	
17	@RestControllerAdvice
18	public class GlobalExceptionHandler {
19	
20	    @ExceptionHandler(BusinessException.class)
21	    public ResponseEntity<ApiResponse<Object>> handleBusiness(BusinessException ex) {
22	        ApiResponse<Object> response = new ApiResponse<>();
23	        response.setCode(ex.getErrorCode().getCode());
24	        response.setMessage(ex.getMessage());
25	        if (ex instanceof ConflictException conflictException) {
26	            response.setData(conflictException.getDetails());
27	        }
28	        response.setTimestamp(Instant.now().getEpochSecond());
29	        return ResponseEntity.status(ex.getStatus()).body(response);
30	    }
31	
32	    @ExceptionHandler(MethodArgumentNotValidException.class)
33	    public ResponseEntity<ApiResponse<Void>> handleValidation(MethodArgumentNotValidException ex) {
34	        List<ErrorDetail> details = ex.getBindingResult()
35	                .getFieldErrors()
36	                .stream()
37	                .map(this::toErrorDetail)
38	                .collect(Collectors.toList());
39	
40	        ApiResponse<Void> response = new ApiResponse<>();
41	        response.setCode(ErrorCode.VALIDATION_FAILED.getCode());
42	        response.setMessage("Validation failed");
43	        response.setErrors(details);
44	        response.setTimestamp(Instant.now().getEpochSecond());
45	        return ResponseEntity.badRequest().body(response);
46	    }
47	
48	    @ExceptionHandler(ConstraintViolationException.class)
49	    public ResponseEntity<ApiResponse<Void>> handleConstraint(ConstraintViolationException ex) {
50	        List<ErrorDetail> details = ex.getConstraintViolations()
51	                .stream()
52	                .map(v -> new ErrorDetail(v.getPropertyPath().toString(), v.getMessage()))
53	                .collect(Collectors.toList());
54	
55	        ApiResponse<Void> response = new ApiResponse<>();
56	        response.setCode(ErrorCode.VALIDATION_FAILED.getCode());
57	        response.setMessage("Validation failed");
58	        response.setErrors(details);
59	        response.setTimestamp(Instant.now().getEpochSecond());
60	        return ResponseEntity.badRequest().body(response);
61	    }
62	
63	    @ExceptionHandler(Exception.class)
64	    public ResponseEntity<ApiResponse<Void>> handleGeneric(Exception ex) {
65	        ApiResponse<Void> response = new ApiResponse<>();
66	        response.setCode(ErrorCode.INTERNAL_ERROR.getCode());
67	        response.setMessage("Internal server error");
68	        response.setTimestamp(Instant.now().getEpochSecond());
69	        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
70	                .header(HttpHeaders.CONNECTION, "close")
71	                .body(response);
72	    }
73	
74	    private ErrorDetail toErrorDetail(FieldError fieldError) {
75	        return new ErrorDetail(fieldError.getField(), fieldError.getDefaultMessage());
76	    }
77	}
