1	package com.exam.system.service.impl.notification;
2	
3	import com.exam.system.dto.notification.NotificationTargetScopeDto;
4	import com.exam.system.entity.JobRecord;
5	import com.exam.system.entity.NotifDelivery;
6	import com.exam.system.entity.NotifPreference;
7	import com.exam.system.entity.Notification;
8	import com.exam.system.entity.NotificationChannel;
9	import com.exam.system.entity.SysUser;
10	import com.exam.system.exception.BusinessException;
11	import com.exam.system.exception.ErrorCode;
12	import com.exam.system.notification.DeliveryStatus;
13	import com.exam.system.notification.NotificationPublishedEvent;
14	import com.exam.system.notification.NotificationStatus;
15	import com.exam.system.job.JobQueueService;
16	import com.exam.system.job.JobType;
17	import com.exam.system.repository.NotifDeliveryRepository;
18	import com.exam.system.repository.NotifPreferenceRepository;
19	import com.exam.system.repository.NotificationRepository;
20	import com.exam.system.repository.SysUserRepository;
21	import com.exam.system.service.impl.delivery.DeliveryAttemptResult;
22	import com.exam.system.service.impl.delivery.NotificationDeliveryStrategy;
23	import java.time.LocalDate;
24	import java.time.LocalDateTime;
25	import java.time.LocalTime;
26	import java.util.HashMap;
27	import java.util.List;
28	import java.util.Map;
29	import java.util.Optional;
30	import java.util.Set;
31	import java.util.regex.Matcher;
32	import java.util.regex.Pattern;
33	import org.springframework.context.event.EventListener;
34	import org.springframework.http.HttpStatus;
35	import org.springframework.stereotype.Component;
36	import org.springframework.transaction.annotation.Transactional;
37	
38	@Component
39	public class NotificationDeliveryPipeline {
40	
41	    private final NotificationRepository notificationRepository;
42	    private final NotifDeliveryRepository deliveryRepository;
43	    private final NotifPreferenceRepository preferenceRepository;
44	    private final SysUserRepository userRepository;
45	    private final JobQueueService jobQueueService;
46	    private final NotificationTargetResolver targetResolver;
47	    private final NotificationScopeParser scopeParser;
48	    private final Map<NotificationChannel, NotificationDeliveryStrategy> strategies;
49	
50	    public NotificationDeliveryPipeline(NotificationRepository notificationRepository,
51	                                        NotifDeliveryRepository deliveryRepository,
52	                                        NotifPreferenceRepository preferenceRepository,
53	                                        SysUserRepository userRepository,
54	                                        JobQueueService jobQueueService,
55	                                        NotificationTargetResolver targetResolver,
56	                                        NotificationScopeParser scopeParser,
57	                                        List<NotificationDeliveryStrategy> strategyList) {
58	        this.notificationRepository = notificationRepository;
59	        this.deliveryRepository = deliveryRepository;
60	        this.preferenceRepository = preferenceRepository;
61	        this.userRepository = userRepository;
62	        this.jobQueueService = jobQueueService;
63	        this.targetResolver = targetResolver;
64	        this.scopeParser = scopeParser;
65	        this.strategies = new HashMap<>();
66	        for (NotificationDeliveryStrategy strategy : strategyList) {
67	            this.strategies.put(strategy.channel(), strategy);
68	        }
69	    }
70	
71	    @EventListener
72	    @Transactional
73	    public void onPublished(NotificationPublishedEvent event) {
74	        Notification notification = notificationRepository.findById(event.getNotificationId())
75	                .orElseThrow(() -> new BusinessException(ErrorCode.RESOURCE_NOT_FOUND, HttpStatus.NOT_FOUND, "Notification not found"));
76	        jobQueueService.enqueue(
77	                JobType.NOTIFICATION_SEND,
78	                "send-notification-" + notification.getId(),
79	                "{\"notificationId\":" + notification.getId() + "}");
80	    }
81	
82	    @Transactional
83	    public void retryDelivery(Long deliveryId) {
84	        NotifDelivery delivery = deliveryRepository.findById(deliveryId)
85	                .orElseThrow(() -> new BusinessException(ErrorCode.RESOURCE_NOT_FOUND, HttpStatus.NOT_FOUND, "Delivery not found"));
86	        attemptDelivery(delivery, true);
87	    }
88	
89	    @Transactional
90	    public void executeNotificationSend(JobRecord jobRecord) {
91	        Long notificationId = extractLong(jobRecord.getPayloadJson(), "notificationId");
92	        Notification notification = notificationRepository.findById(notificationId)
93	                .orElseThrow(() -> new BusinessException(ErrorCode.RESOURCE_NOT_FOUND, HttpStatus.NOT_FOUND, "Notification not found"));
94	        createRecipientDeliveries(notification);
95	        notification.setStatus(NotificationStatus.SENT);
96	        notificationRepository.save(notification);
97	    }
98	
99	    @Transactional
100	    public void executeRetryDelivery(JobRecord jobRecord) {
101	        Long deliveryId = extractLong(jobRecord.getPayloadJson(), "deliveryId");
102	        NotifDelivery delivery = deliveryRepository.findById(deliveryId)
103	                .orElseThrow(() -> new BusinessException(ErrorCode.RESOURCE_NOT_FOUND, HttpStatus.NOT_FOUND, "Delivery not found"));
104	        attemptDelivery(delivery, false);
105	    }
106	
107	    @Transactional
108	    public void executeDndRelease(JobRecord jobRecord) {
109	        List<NotifDelivery> held = deliveryRepository.findByStatus(DeliveryStatus.HELD_DND);
110	        for (NotifDelivery delivery : held) {
111	            Notification notification = notificationRepository.findById(delivery.getNotificationId()).orElse(null);
112	            SysUser user = userRepository.findById(delivery.getRecipientId()).orElse(null);
113	            if (notification == null || user == null) {
114	                continue;
115	            }
116	            if (!isWithinDnd(user.getId(), notification.getEventType())) {
117	                attemptDelivery(delivery, false);
118	            }
119	        }
120	    }
121	
122	    private void createRecipientDeliveries(Notification notification) {
123	        NotificationTargetScopeDto scope = scopeParser.fromJson(notification.getTargetScope());
124	        Set<Long> recipients = targetResolver.resolveStudentRecipientIds(scope);
125	
126	        for (Long recipientId : recipients) {
127	            NotifDelivery delivery = new NotifDelivery();
128	            delivery.setNotificationId(notification.getId());
129	            delivery.setRecipientId(recipientId);
130	            delivery.setChannel(NotificationChannel.APP);
131	            delivery.setStatus(DeliveryStatus.PENDING);
132	            delivery.setAttempts(0);
133	            deliveryRepository.save(delivery);
134	
135	            attemptDelivery(delivery, false);
136	        }
137	    }
138	
139	    private void attemptDelivery(NotifDelivery delivery, boolean manualRetry) {
140	        Notification notification = notificationRepository.findById(delivery.getNotificationId())
141	                .orElseThrow(() -> new BusinessException(ErrorCode.RESOURCE_NOT_FOUND, HttpStatus.NOT_FOUND, "Notification not found"));
142	        SysUser user = userRepository.findById(delivery.getRecipientId())
143	                .orElseThrow(() -> new BusinessException(ErrorCode.RESOURCE_NOT_FOUND, HttpStatus.NOT_FOUND, "Recipient not found"));
144	
145	        Optional<NotifPreference> preference = preferenceRepository.findByUserIdAndEventType(user.getId(), notification.getEventType());
146	        if (preference.isPresent() && !preference.get().isEnabled()) {
147	            delivery.setStatus(DeliveryStatus.FAILED);
148	            deliveryRepository.save(delivery);
149	            return;
150	        }
151	
152	        if (!"HIGH".equalsIgnoreCase(notification.getPriority()) && isWithinDnd(user.getId(), notification.getEventType())) {
153	            delivery.setStatus(DeliveryStatus.HELD_DND);
154	            deliveryRepository.save(delivery);
155	            return;
156	        }
157	
158	        delivery.setStatus(DeliveryStatus.SENDING);
159	        delivery.setLastAttemptAt(LocalDateTime.now());
160	        delivery.setAttempts(delivery.getAttempts() + 1);
161	
162	        NotificationDeliveryStrategy wechat = strategies.get(NotificationChannel.WECHAT);
163	        NotificationDeliveryStrategy inApp = strategies.get(NotificationChannel.APP);
164	
165	        DeliveryAttemptResult result;
166	        NotificationChannel usedChannel;
167	        if (wechat != null && wechat.supports(user)) {
168	            result = wechat.deliver(notification, delivery, user);
169	            usedChannel = NotificationChannel.WECHAT;
170	            if (!result.isSuccess() && result.isChannelUnavailable() && inApp != null) {
171	                result = inApp.deliver(notification, delivery, user);
172	                usedChannel = NotificationChannel.APP;
173	            }
174	        } else {
175	            result = inApp.deliver(notification, delivery, user);
176	            usedChannel = NotificationChannel.APP;
177	        }
178	
179	        delivery.setChannel(usedChannel);
180	        if (result.isSuccess()) {
181	            delivery.setStatus(DeliveryStatus.DELIVERED);
182	            delivery.setDeliveredAt(LocalDateTime.now());
183	            deliveryRepository.save(delivery);
184	            return;
185	        }
186	
187	        if (manualRetry) {
188	            delivery.setStatus(DeliveryStatus.FAILED);
189	            deliveryRepository.save(delivery);
190	            return;
191	        }
192	
193	        if (delivery.getAttempts() >= 3) {
194	            delivery.setStatus(DeliveryStatus.FAILED);
195	            deliveryRepository.save(delivery);
196	            return;
197	        }
198	
199	        delivery.setStatus(DeliveryStatus.PENDING);
200	        deliveryRepository.save(delivery);
201	
202	        LocalDateTime nextRetry = LocalDateTime.now().plusMinutes(backoffMinutes(delivery.getAttempts()));
203	        jobQueueService.enqueue(
204	                JobType.RETRY_DELIVERY,
205	                "retry-delivery-" + delivery.getId() + "-" + delivery.getAttempts(),
206	                "{\"deliveryId\":" + delivery.getId() + "}",
207	                nextRetry);
208	    }
209	
210	    private Long extractLong(String payload, String key) {
211	        if (payload == null || payload.isBlank()) {
212	            throw new IllegalStateException("Missing payload");
213	        }
214	        Pattern pattern = Pattern.compile("\\\"" + Pattern.quote(key) + "\\\"\\s*:\\s*(\\d+)");
215	        Matcher matcher = pattern.matcher(payload);
216	        if (!matcher.find()) {
217	            throw new IllegalStateException("Invalid payload for key " + key);
218	        }
219	        return Long.parseLong(matcher.group(1));
220	    }
221	
222	    private int backoffMinutes(int attempt) {
223	        return switch (attempt) {
224	            case 1 -> 1;
225	            case 2 -> 5;
226	            default -> 15;
227	        };
228	    }
229	
230	    private boolean isWithinDnd(Long userId, String eventType) {
231	        Optional<NotifPreference> pref = preferenceRepository.findByUserIdAndEventType(userId, eventType);
232	        if (pref.isEmpty() || pref.get().getDndStart() == null || pref.get().getDndEnd() == null) {
233	            return false;
234	        }
235	        LocalTime now = LocalTime.now();
236	        LocalTime start = pref.get().getDndStart();
237	        LocalTime end = pref.get().getDndEnd();
238	
239	        if (start.equals(end)) {
240	            return false;
241	        }
242	        if (start.isBefore(end)) {
243	            return !now.isBefore(start) && now.isBefore(end);
244	        }
245	        return !now.isBefore(start) || now.isBefore(end);
246	    }
247	}
