1	package com.exam.system.security.filter;
2	
3	import com.exam.system.config.JsonResponseWriter;
4	import com.exam.system.exception.ErrorCode;
5	import com.exam.system.security.rbac.UserContext;
6	import com.exam.system.security.rbac.UserContextHolder;
7	import com.exam.system.service.SessionService;
8	import jakarta.servlet.FilterChain;
9	import jakarta.servlet.ServletException;
10	import jakarta.servlet.http.HttpServletRequest;
11	import jakarta.servlet.http.HttpServletResponse;
12	import java.io.IOException;
13	import org.springframework.http.HttpStatus;
14	import org.springframework.stereotype.Component;
15	import org.springframework.web.filter.OncePerRequestFilter;
16	
17	/**
18	 * Token-based authentication filter and request user-context injection.
19	 */
20	@Component
21	public class AuthFilter extends OncePerRequestFilter {
22	
23	    private final SessionService sessionService;
24	    private final JsonResponseWriter jsonResponseWriter;
25	
26	    public AuthFilter(SessionService sessionService, JsonResponseWriter jsonResponseWriter) {
27	        this.sessionService = sessionService;
28	        this.jsonResponseWriter = jsonResponseWriter;
29	    }
30	
31	    @Override
32	    protected boolean shouldNotFilter(HttpServletRequest request) {
33	        String uri = request.getRequestURI();
34	        if ("OPTIONS".equalsIgnoreCase(request.getMethod())) {
35	            return true;
36	        }
37	        return ("POST".equalsIgnoreCase(request.getMethod()) && "/api/v1/auth/login".equals(uri));
38	    }
39	
40	    @Override
41	    protected void doFilterInternal(HttpServletRequest request,
42	                                    HttpServletResponse response,
43	                                    FilterChain filterChain) throws ServletException, IOException {
44	        String authorization = request.getHeader("Authorization");
45	        if (authorization == null || !authorization.startsWith("Bearer ")) {
46	            jsonResponseWriter.writeError(response, HttpStatus.UNAUTHORIZED.value(),
47	                    ErrorCode.SESSION_INVALID, "Missing or invalid Authorization header");
48	            return;
49	        }
50	
51	        String token = authorization.substring(7);
52	        UserContext context = sessionService.resolve(token).orElse(null);
53	        if (context == null) {
54	            jsonResponseWriter.writeError(response, HttpStatus.UNAUTHORIZED.value(),
55	                    ErrorCode.SESSION_INVALID, "Session is invalid or expired");
56	            return;
57	        }
58	
59	        try {
60	            UserContextHolder.set(context);
61	            filterChain.doFilter(request, response);
62	        } finally {
63	            UserContextHolder.clear();
64	        }
65	    }
66	}
