1	package com.exam.system.security.filter;
2	
3	import com.exam.system.config.JsonResponseWriter;
4	import com.exam.system.config.SecurityProperties;
5	import com.exam.system.exception.ErrorCode;
6	import com.exam.system.security.crypto.HmacCryptoService;
7	import com.exam.system.service.RequestNonceService;
8	import jakarta.servlet.FilterChain;
9	import jakarta.servlet.ServletException;
10	import jakarta.servlet.http.HttpServletRequest;
11	import jakarta.servlet.http.HttpServletResponse;
12	import java.io.IOException;
13	import java.time.Instant;
14	import org.springframework.http.HttpStatus;
15	import org.springframework.stereotype.Component;
16	import org.springframework.web.filter.OncePerRequestFilter;
17	
18	/**
19	 * Prevents replay attacks with timestamp, nonce and request signature checks.
20	 */
21	@Component
22	public class ReplayGuardFilter extends OncePerRequestFilter {
23	
24	    private final SecurityProperties securityProperties;
25	    private final RequestNonceService requestNonceService;
26	    private final HmacCryptoService hmacCryptoService;
27	    private final JsonResponseWriter jsonResponseWriter;
28	
29	    public ReplayGuardFilter(SecurityProperties securityProperties,
30	                             RequestNonceService requestNonceService,
31	                             HmacCryptoService hmacCryptoService,
32	                             JsonResponseWriter jsonResponseWriter) {
33	        this.securityProperties = securityProperties;
34	        this.requestNonceService = requestNonceService;
35	        this.hmacCryptoService = hmacCryptoService;
36	        this.jsonResponseWriter = jsonResponseWriter;
37	    }
38	
39	    @Override
40	    protected boolean shouldNotFilter(HttpServletRequest request) {
41	        if ("OPTIONS".equalsIgnoreCase(request.getMethod())) {
42	            return true;
43	        }
44	        return "POST".equalsIgnoreCase(request.getMethod())
45	                && "/api/v1/auth/login".equals(request.getRequestURI());
46	    }
47	
48	    @Override
49	    protected void doFilterInternal(HttpServletRequest request,
50	                                    HttpServletResponse response,
51	                                    FilterChain filterChain) throws ServletException, IOException {
52	        String timestampHeader = request.getHeader("X-Timestamp");
53	        String nonce = request.getHeader("X-Nonce");
54	        String signature = request.getHeader("X-Signature");
55	
56	        if (timestampHeader == null || nonce == null || signature == null) {
57	            jsonResponseWriter.writeError(response, HttpStatus.UNAUTHORIZED.value(),
58	                    ErrorCode.REPLAY_VALIDATION_FAILED, "Missing replay-guard headers");
59	            return;
60	        }
61	
62	        long timestamp;
63	        try {
64	            timestamp = Long.parseLong(timestampHeader);
65	        } catch (NumberFormatException ex) {
66	            jsonResponseWriter.writeError(response, HttpStatus.UNAUTHORIZED.value(),
67	                    ErrorCode.REPLAY_VALIDATION_FAILED, "Invalid X-Timestamp value");
68	            return;
69	        }
70	
71	        long now = Instant.now().getEpochSecond();
72	        if (Math.abs(now - timestamp) > securityProperties.getReplayWindowSeconds()) {
73	            jsonResponseWriter.writeError(response, HttpStatus.UNAUTHORIZED.value(),
74	                    ErrorCode.REPLAY_VALIDATION_FAILED, "Request timestamp is outside the allowed window");
75	            return;
76	        }
77	
78	        if (requestNonceService.isDuplicate(nonce)) {
79	            jsonResponseWriter.writeError(response, HttpStatus.UNAUTHORIZED.value(),
80	                    ErrorCode.REPLAY_VALIDATION_FAILED, "Duplicate nonce detected");
81	            return;
82	        }
83	
84	        CachedBodyRequestWrapper wrappedRequest = new CachedBodyRequestWrapper(request);
85	        String bodyHash = HashUtils.sha256Hex(wrappedRequest.getCachedBody());
86	        String payload = wrappedRequest.getMethod() + wrappedRequest.getRequestURI() + timestampHeader + nonce + bodyHash;
87	
88	        if (!hmacCryptoService.verify(payload, signature)) {
89	            jsonResponseWriter.writeError(response, HttpStatus.UNAUTHORIZED.value(),
90	                    ErrorCode.REPLAY_VALIDATION_FAILED, "Invalid request signature");
91	            return;
92	        }
93	
94	        requestNonceService.save(nonce, securityProperties.getReplayWindowSeconds());
95	        filterChain.doFilter(wrappedRequest, response);
96	    }
97	}
