1	package com.exam.system.security.crypto;
2	
3	import java.nio.charset.StandardCharsets;
4	import javax.crypto.Mac;
5	import javax.crypto.spec.SecretKeySpec;
6	import org.springframework.beans.factory.annotation.Value;
7	import org.springframework.stereotype.Component;
8	
9	@Component
10	public class HmacCryptoService {
11	
12	    private final String secret;
13	
14	    public HmacCryptoService(@Value("${app.security.hmac-secret}") String secret) {
15	        this.secret = secret;
16	    }
17	
18	    public String sign(String payload) {
19	        try {
20	            Mac mac = Mac.getInstance("HmacSHA256");
21	            mac.init(new SecretKeySpec(secret.getBytes(StandardCharsets.UTF_8), "HmacSHA256"));
22	            byte[] raw = mac.doFinal(payload.getBytes(StandardCharsets.UTF_8));
23	            return toHex(raw);
24	        } catch (Exception ex) {
25	            throw new IllegalStateException("Unable to compute HMAC", ex);
26	        }
27	    }
28	
29	    public boolean verify(String payload, String signature) {
30	        String expected = sign(payload);
31	        return constantTimeEquals(expected, signature);
32	    }
33	
34	    private boolean constantTimeEquals(String left, String right) {
35	        if (left == null || right == null || left.length() != right.length()) {
36	            return false;
37	        }
38	        int result = 0;
39	        for (int i = 0; i < left.length(); i++) {
40	            result |= left.charAt(i) ^ right.charAt(i);
41	        }
42	        return result == 0;
43	    }
44	
45	    private String toHex(byte[] bytes) {
46	        StringBuilder sb = new StringBuilder(bytes.length * 2);
47	        for (byte b : bytes) {
48	            sb.append(String.format("%02x", b));
49	        }
50	        return sb.toString();
51	    }
52	}
