3	import java.nio.charset.StandardCharsets;
4	import java.security.MessageDigest;
5	
6	public final class HashUtils {
7	
8	    private HashUtils() {
9	    }
10	
11	    public static String sha256Hex(byte[] input) {
12	        try {
13	            MessageDigest digest = MessageDigest.getInstance("SHA-256");
14	            byte[] hash = digest.digest(input);
15	            StringBuilder sb = new StringBuilder(hash.length * 2);
16	            for (byte b : hash) {
17	                sb.append(String.format("%02x", b));
18	            }
19	            return sb.toString();
20	        } catch (Exception ex) {
21	            throw new IllegalStateException("Unable to hash payload", ex);
22	        }
23	    }
24	
25	    public static String sha256Hex(String input) {
26	        return sha256Hex(input.getBytes(StandardCharsets.UTF_8));
27	    }
28	}
