27	/**
28	 * Authentication and session APIs under /api/v1/auth.
29	 */
30	@RestController
31	@RequestMapping("/api/v1/auth")
32	public class AuthController {
33	
34	    private final AuthService authService;
35	
36	    public AuthController(AuthService authService) {
37	        this.authService = authService;
38	    }
39	
40	    @PostMapping("/login")
41	    public ResponseEntity<ApiResponse<LoginResponse>> login(@Valid @RequestBody LoginRequest request,
42	                                                            HttpServletRequest servletRequest) {
43	        String ip = servletRequest.getRemoteAddr();
44	        String fingerprint = servletRequest.getHeader("User-Agent");
45	        LoginResponse response = authService.login(request, ip, fingerprint);
46	        return ResponseEntity.ok(ApiResponse.success(response));
47	    }
48	
49	    @PostMapping("/logout")
50	    public ResponseEntity<Void> logout(@RequestHeader("Authorization") String authorization) {
51	        authService.logout(extractToken(authorization));
52	        return ResponseEntity.noContent().build();
53	    }
54	
55	    @PutMapping("/active-role")
56	    public ResponseEntity<ApiResponse<SwitchRoleResponse>> switchRole(@Valid @RequestBody SwitchRoleRequest request,
57	                                                                      @RequestHeader("Authorization") String authorization) {
58	        UserContext context = requireContext();
59	        SwitchRoleResponse response = authService.switchActiveRole(context.getUserId(), extractToken(authorization), request.getRole());
60	        return ResponseEntity.ok(ApiResponse.success(response));
61	    }
62	
63	    @GetMapping("/me")
64	    public ResponseEntity<ApiResponse<UserProfileDto>> me(@RequestHeader("Authorization") String authorization) {
65	        UserContext context = requireContext();
66	        UserProfileDto data = authService.me(context.getUserId(), extractToken(authorization));
67	        return ResponseEntity.ok(ApiResponse.success(data));
68	    }
69	
70	    @PutMapping("/password")
71	    public ResponseEntity<ApiResponse<Void>> changePassword(@Valid @RequestBody ChangePasswordRequest request) {
72	        UserContext context = requireContext();
73	        authService.changePassword(context.getUserId(), request);
74	        return ResponseEntity.ok(ApiResponse.successMessage("Password changed successfully"));
75	    }
76	
77	    private UserContext requireContext() {
78	        UserContext context = UserContextHolder.get();
79	        if (context == null) {
80	            throw new BusinessException(ErrorCode.SESSION_INVALID, HttpStatus.UNAUTHORIZED, "Unauthorized");
81	        }
82	        return context;
83	    }
84	
85	    private String extractToken(String authorization) {
86	        if (authorization == null || !authorization.startsWith("Bearer ")) {
87	            throw new BusinessException(ErrorCode.SESSION_INVALID, HttpStatus.UNAUTHORIZED,
88	                    "Missing Bearer token");
89	        }
90	        return authorization.substring(7);
91	    }
92	}
